mapper.insert:
	INSERT INTO PIN_USR_MGT (
	  USER_BANKING_ID    /* 사용자 뱅킹 id */
    , DEVICE_ID          /* 사용자 기기 id (PK) */
    , DEVICE_TYPE        /* 사용자 기기 type */
    , JOIN_FLAG          /* 가입 유무 */
    , DEVICE_ID_UPDATE   /* 사용자 기기 id update여부 */
    , POPUP_STATUS       /* 가입 팝업 유무 */
    , JOIN_DT            /* 최초가입일자 */
    , LAST_UPDATE_DT     /* 최근 업데이트 날짜 */
    , NICK_NAME          /* 사용자 닉네임 */
	) 
	VALUES (
      #{userBankingId}  
    , #{deviceId}
    , #{deviceType}
    , #{joinFlag}
    , #{deviceIdUpdate}
    , #{popupStatus}
    , CURRENT TIMESTAMP
    , CURRENT TIMESTAMP
    , #{nickName}
	)
